document.addEventListener("DOMContentLoaded",(()=>{document.querySelectorAll('a[data-allowed="0"]').forEach((e=>{e.classList.add("is-disabled"),e.setAttribute("aria-disabled","true"),e.setAttribute("tabindex","-1");const block=e=>{e.preventDefault(),e.stopPropagation()};e.addEventListener("click",block),e.addEventListener("keydown",(e=>{"Enter"!==e.key&&" "!==e.key||block(e)}))}))}));